/**
 * Classifies a parcel weight into a bracket: "standard", "heavy", or "freight".
 *
 * Brackets:
 *   standard:  0 < weight < 10
 *   heavy:    10 <= weight < 50
 *   freight:  50 <= weight <= 1000
 *
 * Throws a validation error for weight <= 0 or weight > 1000.
 */
