  constructor(weight: number) {
    super(`Invalid weight: ${weight}. Weight must be > 0 and <= 1000.`);
    this.name = "WeightValidationError";
  }
}

export function classifyWeight(weight: number): WeightBracket {
  if (weight <= 0 || weight > 1000) {
    throw new WeightValidationError(weight);
  }

  if (weight < 10) {
    return "standard";
  }

  if (weight < 50) {
    return "heavy";
  }

  return "freight";
}

